using System;
using System.Globalization;
using TMPro;
using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// Botão de um slot do Menu de Save (Etapa de Menu de Save): mostra a
/// pré-visualização de um save (área/mundo, data/hora, corações) ou, se
/// vazio, um estado "Sem dados"/"Criar novo save". Instanciado e configurado
/// por <see cref="SaveMenuController"/>.
///
/// Prefab esperado (montar no Editor): Button + filhos com TMP_Text para
/// "titleText" (nome da área/mundo ou "Criar Novo Save"/"Autoguardar") e
/// "infoText" (data/hora + corações, ou texto vazio).
/// </summary>
public class SaveSlotButtonUI : MonoBehaviour
{
    /// <summary>Tipo de slot representado por este botão.</summary>
    public enum SlotKind
    {
        /// <summary>Slot de autoguardar (topo do menu, único).</summary>
        Auto,

        /// <summary>Slot manual já usado (0-29) — overwrite (Guardar) ou carregar (Carregar).</summary>
        Manual,

        /// <summary>Botão "Criar Novo Save" — cria o próximo slot manual livre. Só aparece em modo Guardar e enquanto houver slots livres.</summary>
        CreateNew
    }

    [Header("Referências")]
    [SerializeField] private Button button;
    [SerializeField] private TMP_Text titleText;
    [SerializeField] private TMP_Text infoText;

    [Header("Apagar (opcional — só slots manuais usados)")]
    [Tooltip("Botão 'Apagar' opcional, mostrado apenas para slots manuais já usados (SlotKind.Manual com dados). Deixar vazio se o menu não suportar apagar saves.")]
    [SerializeField] private Button deleteButton;

    /// <summary>Disparado quando este botão é clicado, com a própria instância (controller lê Kind/SlotIndex).</summary>
    public event Action<SaveSlotButtonUI> Clicked;

    /// <summary>Disparado quando o botão "Apagar" deste slot é clicado, com a própria instância (controller lê SlotIndex).</summary>
    public event Action<SaveSlotButtonUI> DeleteClicked;

    public SlotKind Kind { get; private set; }

    /// <summary>-1 para o slot de autoguardar; 0-29 para slots manuais (incluindo "Criar Novo Save", que usa o próximo slot livre).</summary>
    public int SlotIndex { get; private set; }

    private void Awake()
    {
        if (button == null) button = GetComponent<Button>();
        button.onClick.AddListener(() => Clicked?.Invoke(this));

        if (deleteButton != null) deleteButton.onClick.AddListener(() => DeleteClicked?.Invoke(this));
    }

    /// <summary>
    /// Configura o botão para o slot de autoguardar.
    /// "data" é null se ainda não existir nenhum autoguardar.
    /// </summary>
    public void SetupAuto(SaveData data, bool interactable)
    {
        Kind = SlotKind.Auto;
        SlotIndex = -1;

        if (data == null)
        {
            SetTexts("Autoguardar", "— vazio —");
        }
        else
        {
            SetTexts("Autoguardar", BuildInfoLine(data));
        }

        button.interactable = interactable;
        SetDeleteVisible(false);
    }

    /// <summary>Configura o botão para um slot manual já usado (0-29).</summary>
    public void SetupManual(int slotIndex, SaveData data)
    {
        Kind = SlotKind.Manual;
        SlotIndex = slotIndex;

        string title = $"Save {slotIndex + 1:00}";
        SetTexts(title, data != null ? BuildInfoLine(data) : "— vazio —");

        button.interactable = true;
        SetDeleteVisible(data != null);
    }

    /// <summary>Configura o botão "Criar Novo Save" (próximo slot manual livre).</summary>
    public void SetupCreateNew(int nextFreeSlotIndex)
    {
        Kind = SlotKind.CreateNew;
        SlotIndex = nextFreeSlotIndex;

        SetTexts("+ Criar Novo Save", "");
        button.interactable = nextFreeSlotIndex >= 0;
        SetDeleteVisible(false);
    }

    private void SetDeleteVisible(bool visible)
    {
        if (deleteButton != null) deleteButton.gameObject.SetActive(visible);
    }

    private void SetTexts(string title, string info)
    {
        if (titleText != null) titleText.text = title;
        if (infoText != null) infoText.text = info;
    }

    /// <summary>Linha de pré-visualização: área/mundo actual + data/hora + corações.</summary>
    private static string BuildInfoLine(SaveData data)
    {
        string place = ResolvePlaceName(data);
        string when = FormatTimestamp(data.timestamp);
        return $"{place}\n{when}  •  {data.currentHearts}/{data.maxHearts} ♥";
    }

    private static string ResolvePlaceName(SaveData data)
    {
        var db = GameDatabase.Instance;

        if (db != null)
        {
            var area = db.FindArea(data.currentAreaId);
            if (area != null && !string.IsNullOrEmpty(area.displayName)) return area.displayName;

            var world = db.FindWorld(data.currentWorldId);
            if (world != null && !string.IsNullOrEmpty(world.displayName)) return world.displayName;
        }

        return !string.IsNullOrEmpty(data.currentAreaId) ? data.currentAreaId : "?";
    }

    private static string FormatTimestamp(string isoTimestamp)
    {
        if (string.IsNullOrEmpty(isoTimestamp)) return "";

        if (DateTime.TryParse(isoTimestamp, CultureInfo.InvariantCulture, DateTimeStyles.RoundtripKind, out var dt))
            return dt.ToLocalTime().ToString("dd/MM/yyyy HH:mm");

        return isoTimestamp;
    }
}
